import pytest
import requests

def test_update_document_unauthenticated_returns_401(admin_auth_token, create_document, api_base_url):
    doc_id = create_document(admin_auth_token)
    payload = {"title": "No Auth Title", "content": "Some content", "category": "HR"}
    resp = requests.put(
        f"{api_base_url}/api/documents/{doc_id}",
        json=payload
    )
    assert resp.status_code == 401, f"Expected 401 without auth, got {resp.status_code}"

import pytest
import requests

def test_update_document_forbidden_role_returns_403(admin_auth_token, non_admin_auth_token, create_document, api_base_url):
    doc_id = create_document(admin_auth_token)
    headers = {"Authorization": f"Bearer {non_admin_auth_token}", "Content-Type": "application/json"}
    payload = {"title": "Forbidden Update", "content": "Should be denied", "category": "HR"}
    resp = requests.put(
        f"{api_base_url}/api/documents/{doc_id}",
        json=payload,
        headers=headers
    )
    assert resp.status_code == 403, f"Expected 403 for non-admin role, got {resp.status_code}"
